    "faq.subtitle": "\u0412\u0441\u0451, \u0447\u0442\u043e \u043d\u0443\u0436\u043d\u043e \u0437\u043d\u0430\u0442\u044c \u043e \u0446\u0435\u043d\u0430\u0445, \u043a\u0440\u0435\u0434\u0438\u0442\u0430\u0445 \u0438 \u0440\u0430\u0431\u043e\u0442\u0435 \u043f\u043b\u0430\u0442\u0444\u043e\u0440\u043c\u044b.",
