    "faq.a1": "\u0531\u0574\u0565\u0576 \u0561\u0576\u0563\u0561\u0574, \u0565\u0580\u0562 \u0564\u0578\u0582\u0584 \u0578\u0582\u0572\u0561\u0580\u056f\u0578\u0582\u0574 \u0565\u0584 \u0561\u057a\u0580\u0561\u0576\u0584\u056b \u056c\u0578\u0582\u057d\u0561\u0576\u056f\u0561\u0580 \u0587 AI-\u0576 \u0570\u0561\u057b\u0578\u0572\u0578\u0582\u0569\u0575\u0561\u0574\u0562 \u057d\u057f\u0565\u0572\u056e\u0578\u0582\u0574 \u0567 3D \u0574\u0578\u0564\u0565\u056c, \u0564\u0561 \u0570\u0561\u0574\u0561\u0580\u057e\u0578\u0582\u0574 \u0567 \u0574\u0565\u056f \u0563\u0565\u0576\u0565\u0580\u0561\u0581\u056b\u0561: \u0531\u0576\u0570\u0561\u057b\u0578\u0572 \u0563\u0565\u0576\u0565\u0580\u0561\u0581\u056b\u0561\u0576\u0565\u0580\u0568 (\u057d\u0565\u0580\u057e\u0565\u0580\u056b \u057d\u056d\u0561\u056c\u056b \u057a\u0561\u057f\u0573\u0561\u057c\u0578\u057e) \u0579\u0565\u0576 \u0570\u0561\u0576\u057e\u0578\u0582\u0574 \u0584\u057e\u0578\u057f\u0561\u0575\u056b\u0581: \u0546\u0578\u0582\u0575\u0576 \u057a\u0561\u057f\u056f\u0565\u0580\u056b \u056f\u0580\u056f\u0576\u0561\u056f\u056b \u0578\u0582\u0572\u0561\u0580\u056f\u0578\u0582\u0574\u0568 \u0570\u0561\u0574\u0561\u0580\u057e\u0578\u0582\u0574 \u0567 \u0576\u0578\u0580 \u0563\u0565\u0576\u0565\u0580\u0561\u0581\u056b\u0561:",
